323→// ---------------------------------------------------------------------------
324→// Auth Helpers
325→// ---------------------------------------------------------------------------
326→
327→export type TestUser = {
328→  headers: Record<string, string>;
329→  personId: string;
330→};
331→
332→export async function createTestUser(baseUrl: string, suffix: string): Promise<TestUser> {
333→  const email = `test-${Date.now()}-${suffix}@test.local`;
334→  const response = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
335→    method: "POST",
336→    headers: { "Content-Type": "application/json" },
337→    body: JSON.stringify({ name: "Test User", email, password: "test-password-123" }),
338→    redirect: "manual",
339→  });
340→
341→  if (!response.ok) {
342→    const body = await response.text();
343→    throw new Error(`Failed to create test user (${response.status}): ${body}`);
344→  }
345→
346→  const setCookie = response.headers.getSetCookie();
347→  if (!setCookie || setCookie.length === 0) {
348→    throw new Error("Sign-up did not return session cookies");
349→  }
350→
351→  const body = (await response.json()) as { user?: { id?: string } };
352→  const personId = body.user?.id;
353→  if (!personId) {
354→    throw new Error("Sign-up response did not include user.id");
355→  }
356→
357→  const cookieHeader = setCookie.map((c) => c.split(";")[0]).join("; ");
358→  return { headers: { Cookie: cookieHeader }, personId };
359→}
