418→// ---------------------------------------------------------------------------
419→// HTTP Helpers
420→// ---------------------------------------------------------------------------
421→
422→export async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
423→  const response = await fetch(url, init);
424→  if (!response.ok) {
425→    const body = await response.text();
426→    throw new Error(`Request failed (${response.status}) ${url}: ${body}`);
427→  }
428→
429→  return (await response.json()) as T;
430→}
